body {
  /* Fluid line-height: min 1.4, preferred 1.4rem + 0.5vw, max 1.7 */
  line-height: clamp(1.4, 1.4rem + 0.5vw, 1.7);
  /* Fluid letter-spacing: min -0.02em, preferred -0.01em + 0.05vw, max 0.01em */
  letter-spacing: clamp(-0.02em, -0.01em + 0.05vw, 0.01em);
}

h1 {
  /* Fluid font-size example for headings */
  font-size: clamp(2rem, 1.5rem + 3vw, 4rem);
  /* Tighter line-height for headings */
  line-height: clamp(1, 1rem + 0.2vw, 1.2);
  /* Tighter letter-spacing for larger headings */
  letter-spacing: clamp(-0.05em, -0.03em + 0.1vw, -0.01em);
}

/* Alternative with custom properties and calc() for more control */
/* This linearly interpolates between values from a min to max viewport width */
p {
  --min-vw: 320px;
  --max-vw: 1200px;
  --min-line-height: 1.4;
  --max-line-height: 1.7;
  --min-letter-spacing: -0.01em;
  --max-letter-spacing: 0.01em;

  line-height: calc(var(--min-line-height) + (var(--max-line-height) - var(--min-line-height)) * ((100vw - var(--min-vw)) / (var(--max-vw) - var(--min-vw))));
  letter-spacing: calc(var(--min-letter-spacing) + (var(--max-letter-spacing) - var(--min-letter-spacing)) * ((100vw - var(--min-vw)) / (var(--max-vw) - var(--min-vw))));
}
